14	function getManagerScope(req: AuthenticatedRequest): string | undefined {
15	  if (req.user!.role === 'manager') {
16	    if (!req.user!.propertyId) throw new AppError(403, 'FORBIDDEN', 'Manager must be assigned to a property');
17	    if (req.query.propertyId && req.query.propertyId !== req.user!.propertyId)
18	      throw new AppError(403, 'FORBIDDEN', 'Access denied to this property');
19	    return req.user!.propertyId;
20	  }
21	  return undefined;
22	}
