24	/**
25	 * Serialize a list of report rows to a CSV string suitable for writing
26	 * to disk. Extracted from exportReport so the safety properties (RFC
27	 * 4180 quoting + formula injection neutralization) can be unit-tested
28	 * without spinning up the full controller.
29	 *
30	 * Returns an empty string when there are no rows so the caller can
31	 * still create an empty file.
32	 */
33	export function serializeReportRowsToCsv(rows: Record<string, unknown>[]): string {
34	  if (rows.length === 0) return '';
35	  const columns = Object.keys(rows[0]);
36	  return objectsToCsv(rows, columns);
37	}
