1	import crypto from 'crypto';
2	import { v4 as uuidv4 } from 'uuid';
3	import { DataTypes, Model, Op } from 'sequelize';
4	import { sequelize } from '../config/database';
5	import { AppError } from '../utils/errors';
6	
7	export class IdempotencyKey extends Model {
8	  public id!: string;
9	  public key!: string;
10	  public actor_id!: string;
11	  public operation!: string;
12	  public resource_id!: string | null;
13	  public request_hash!: string;
14	  public response_snapshot!: unknown;
15	  public expires_at!: Date;
16	  public created_at!: Date;
17	}
18	
19	IdempotencyKey.init({
20	  id: { type: DataTypes.STRING(36), primaryKey: true },
21	  key: { type: DataTypes.STRING(255), allowNull: false },
22	  actor_id: { type: DataTypes.STRING(36), allowNull: false },
23	  operation: { type: DataTypes.STRING(100), allowNull: false },
24	  resource_id: { type: DataTypes.STRING(255), allowNull: true },
25	  request_hash: { type: DataTypes.STRING(64), allowNull: false },
26	  response_snapshot: { type: DataTypes.JSON, allowNull: true },
27	  expires_at: { type: DataTypes.DATE, allowNull: false },
28	  created_at: { type: DataTypes.DATE, allowNull: false },
29	}, { sequelize, tableName: 'idempotency_keys', timestamps: false, underscored: true });
30	
31	const TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
32	
33	function hashBody(body: unknown): string {
34	  return crypto.createHash('sha256').update(JSON.stringify(body || {})).digest('hex');
35	}
36	
37	/**
38	 * Check idempotency for an update operation.
39	 * Returns stored response if key exists with same hash, or null to proceed.
40	 * Throws 409 if key exists with different hash.
41	 */
42	export async function checkIdempotency(
43	  key: string, actorId: string, operation: string, body: unknown
44	): Promise<unknown | null> {
45	  // Scoped to (key, actor, operation) — same key can be reused across different operations
46	  const existing = await IdempotencyKey.findOne({ where: { key, actor_id: actorId, operation } });
47	  if (!existing) return null; // proceed
48	
49	  if (new Date(existing.expires_at) < new Date()) {
50	    // Expired — delete and proceed
51	    await IdempotencyKey.destroy({ where: { id: existing.id } });
52	    return null;
53	  }
54	
55	  const reqHash = hashBody(body);
56	  if (existing.request_hash === reqHash) {
57	    // Same request — return stored response (replay)
58	    return existing.response_snapshot;
59	  }
60	
61	  // Different body with same key — conflict
62	  throw new AppError(409, 'IDEMPOTENCY_CONFLICT', 'Idempotency key already used with a different request');
63	}
64	
65	/**
66	 * Store the response for an idempotent operation.
67	 */
68	export async function storeIdempotency(
69	  key: string, actorId: string, operation: string, resourceId: string | null, body: unknown, response: unknown
70	): Promise<void> {
71	  await IdempotencyKey.create({
72	    id: uuidv4(), key, actor_id: actorId, operation,
73	    resource_id: resourceId,
74	    request_hash: hashBody(body),
75	    response_snapshot: response,
76	    expires_at: new Date(Date.now() + TTL_MS),
77	    created_at: new Date(),
78	  });
79	}
