139	  // Re-evaluate isProd PER REQUEST so tests that flip NODE_ENV after
140	  // module load still see the right behavior. The cost is one cheap
141	  // string compare per unhandled error, which is negligible.
142	  const isProd = process.env.NODE_ENV === 'production';
143	
