219	export async function addCheckpoint(groupId: string, itemId: string, userId: string, data: { label: string; position: number; description?: string }) {
220	  await assertGroupMember(groupId, userId);
221	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
222	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
223	
224	  const count = await ItineraryCheckpoint.count({ where: { item_id: itemId } });
225	  if (count >= MAX_CHECKPOINTS)
226	    throw new AppError(400, 'VALIDATION_ERROR', `Max ${MAX_CHECKPOINTS} checkpoints per item`);
227	
228	  if (data.position < 1 || data.position > MAX_CHECKPOINTS)
229	    throw new AppError(400, 'VALIDATION_ERROR', `Position must be 1-${MAX_CHECKPOINTS}`);
230	
231	  // Enforce unique position per item
232	  const conflict = await ItineraryCheckpoint.findOne({ where: { item_id: itemId, position: data.position } });
233	  if (conflict) throw new AppError(409, 'CONFLICT', `Position ${data.position} already occupied`);
234	
235	  return ItineraryCheckpoint.create({
236	    id: uuidv4(), item_id: itemId, position: data.position,
237	    label: data.label, description: data.description || null, created_at: new Date(),
238	  });
239	}
