6	export async function listUsers(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
7	  try {
8	    const page = Math.max(1, parseInt(req.query.page as string) || 1);
9	    const limit = Math.min(100, Math.max(1, parseInt(req.query.limit as string) || 20));
10	    const offset = (page - 1) * limit;
11	
12	    const { count, rows } = await User.findAndCountAll({
13	      attributes: { exclude: ['password_hash'] },
14	      order: [['created_at', 'DESC']],
15	      limit,
16	      offset,
17	      paranoid: false,
18	    });
19	
20	    res.status(200).json({
21	      data: rows,
22	      pagination: {
23	        page,
24	        limit,
25	        total: count,
26	        totalPages: Math.ceil(count / limit),
27	      },
28	    });
29	  } catch (err) {
30	    next(err);
31	  }
32	}
