34	export async function getUser(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
35	  try {
36	    const user = await User.findByPk(req.params.id, {
37	      attributes: { exclude: ['password_hash'] },
38	      paranoid: false,
39	    });
40	
41	    if (!user) {
42	      throw new AppError(ErrorCodes.NOT_FOUND.statusCode, ErrorCodes.NOT_FOUND.code, 'User not found');
43	    }
44	
45	    res.status(200).json(user);
46	  } catch (err) {
47	    next(err);
48	  }
49	}
