1	import { Response, NextFunction } from 'express';
2	import fs from 'fs';
3	import path from 'path';
4	import { v4 as uuidv4 } from 'uuid';
5	import ExcelJS from 'exceljs';
6	import { AuthenticatedRequest } from '../middleware/auth.middleware';
7	import * as reportingService from '../services/reporting.service';
8	import { AuditLog } from '../models/audit.model';
9	import { ExportRecord } from '../models/export.model';
10	import { AppError } from '../utils/errors';
11	import { traceStore } from '../utils/logger';
12	import { objectsToCsv } from '../utils/csv';
13	
14	function getManagerScope(req: AuthenticatedRequest): string | undefined {
15	  if (req.user!.role === 'manager') {
16	    if (!req.user!.propertyId) throw new AppError(403, 'FORBIDDEN', 'Manager must be assigned to a property');
17	    if (req.query.propertyId && req.query.propertyId !== req.user!.propertyId)
18	      throw new AppError(403, 'FORBIDDEN', 'Access denied to this property');
19	    return req.user!.propertyId;
20	  }
21	  return undefined;
22	}
23	
24	/**
25	 * Serialize a list of report rows to a CSV string suitable for writing
26	 * to disk. Extracted from exportReport so the safety properties (RFC
27	 * 4180 quoting + formula injection neutralization) can be unit-tested
28	 * without spinning up the full controller.
29	 *
30	 * Returns an empty string when there are no rows so the caller can
31	 * still create an empty file.
32	 */
33	export function serializeReportRowsToCsv(rows: Record<string, unknown>[]): string {
34	  if (rows.length === 0) return '';
35	  const columns = Object.keys(rows[0]);
36	  return objectsToCsv(rows, columns);
37	}
38	
39	export async function occupancy(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
40	  try {
41	    const scope = getManagerScope(req);
42	    res.json(await reportingService.occupancy({ propertyId: req.query.propertyId as string, from: req.query.from as string, to: req.query.to as string, groupBy: req.query.groupBy as string, roomType: req.query.roomType as string }, scope));
43	  } catch (e) { next(e); }
44	}
45	
46	export async function adr(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
47	  try {
48	    const scope = getManagerScope(req);
49	    res.json(await reportingService.adr({ propertyId: req.query.propertyId as string, from: req.query.from as string, to: req.query.to as string, groupBy: req.query.groupBy as string, roomType: req.query.roomType as string }, scope));
50	  } catch (e) { next(e); }
51	}
52	
53	export async function revpar(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
54	  try {
55	    const scope = getManagerScope(req);
56	    res.json(await reportingService.revpar({ propertyId: req.query.propertyId as string, from: req.query.from as string, to: req.query.to as string, groupBy: req.query.groupBy as string, roomType: req.query.roomType as string }, scope));
57	  } catch (e) { next(e); }
58	}
59	
60	export async function revenueMix(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
61	  try {
62	    const scope = getManagerScope(req);
63	    res.json(await reportingService.revenueMix({ propertyId: req.query.propertyId as string, from: req.query.from as string, to: req.query.to as string, groupBy: req.query.groupBy as string }, scope));
64	  } catch (e) { next(e); }
65	}
66	
67	export async function exportReport(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
68	  try {
69	    const scope = getManagerScope(req);
70	    const { reportType, from, to, format, groupBy, propertyId, includePii } = req.body;
71	
72	    if (includePii) {
73	      const { User } = require('../models/user.model');
74	      const user = await User.findByPk(req.user!.id);
75	      if (!user?.pii_export_allowed) throw new AppError(403, 'FORBIDDEN', 'PII export not permitted');
76	    }
77	
78	    let data: unknown[];
79	    switch (reportType) {
80	      case 'occupancy': data = await reportingService.occupancy({ propertyId, from, to, groupBy }, scope); break;
81	      case 'adr': data = await reportingService.adr({ propertyId, from, to, groupBy }, scope); break;
82	      case 'revpar': data = await reportingService.revpar({ propertyId, from, to, groupBy }, scope); break;
83	      case 'revenue_mix': data = await reportingService.revenueMix({ propertyId, from, to, groupBy }, scope); break;
84	      default: throw new AppError(400, 'VALIDATION_ERROR', 'Invalid reportType');
85	    }
86	
87	    const exportId = uuidv4();
88	    const rows = data as Record<string, unknown>[];
89	    let filename: string;
90	    let filePath: string;
91	
92	    if (format === 'excel') {
93	      filename = `report-${reportType}-${exportId}.xlsx`;
94	      filePath = path.resolve('exports', filename);
95	      const wb = new ExcelJS.Workbook();
96	      const ws = wb.addWorksheet(reportType);
97	      if (rows.length > 0) {
98	        ws.addRow(Object.keys(rows[0]));
99	        for (const row of rows) ws.addRow(Object.values(row));
100	      }
101	      await wb.xlsx.writeFile(filePath);
102	    } else {
103	      // CSV — serialized via serializeReportRowsToCsv → objectsToCsv so
104	      // every cell is properly quoted (commas / newlines / embedded
105	      // quotes) and values that begin with formula-trigger characters
106	      // (=, +, -, @) are neutralized against spreadsheet formula
107	      // injection. See src/utils/csv.ts.
108	      filename = `report-${reportType}-${exportId}.csv`;
109	      filePath = path.resolve('exports', filename);
110	      fs.writeFileSync(filePath, serializeReportRowsToCsv(rows));
