1	/**
2	 * CSV safety utilities.
3	 *
4	 * Two concerns:
5	 * 1) Standard RFC 4180 quoting for commas, quotes, newlines, and CR.
6	 * 2) Formula injection neutralization. When a spreadsheet application opens
7	 *    a CSV and a cell begins with `=`, `+`, `-`, `@`, TAB, or CR, it may
8	 *    be interpreted as a formula. We prefix such cells with a single quote
9	 *    (`'`) inside the quoted field to neutralize the behavior.
10	 *
11	 * These helpers are deliberately framework-free so they can be used in any
12	 * export path (audit logs, reports).
13	 */
14	
15	const FORMULA_TRIGGER = /^[=+\-@\t\r]/;
16	
17	/**
18	 * Escape a single CSV cell value. Always returns a quoted string so we can
19	 * safely embed commas/newlines/quotes, and prefixes dangerous formula
20	 * triggers with a single quote to neutralize spreadsheet formula execution.
21	 */
22	export function csvEscapeCell(value: unknown): string {
23	  if (value === null || value === undefined) return '""';
24	
25	  // Serialize objects/arrays to JSON so downstream callers do not need to
26	  // pre-flatten complex values. Primitives are coerced to string.
27	  let str: string;
28	  if (typeof value === 'object') {
29	    try {
30	      str = JSON.stringify(value);
31	    } catch {
32	      str = String(value);
33	    }
34	  } else {
35	    str = String(value);
36	  }
37	
38	  // Neutralize formula injection: prefix with single quote inside the quoted
39	  // field. The leading quote is part of the cell text and is recognized by
40	  // spreadsheet apps as "treat as literal".
41	  if (FORMULA_TRIGGER.test(str)) {
42	    str = `'${str}`;
43	  }
44	
45	  // RFC 4180: escape embedded double quotes by doubling them, then wrap the
46	  // whole cell in double quotes.
47	  return `"${str.replace(/"/g, '""')}"`;
48	}
49	
50	/**
51	 * Render an array of rows (array-of-arrays) as a CSV string. The first row
52	 * is treated as the header. All cells are escaped by csvEscapeCell.
53	 */
54	export function rowsToCsv(rows: unknown[][]): string {
55	  return rows.map((row) => row.map(csvEscapeCell).join(',')).join('\r\n');
56	}
57	
58	/**
59	 * Render an array of row objects as a CSV string using the provided column
60	 * order as headers. Missing keys become empty cells.
61	 */
62	export function objectsToCsv(
63	  objects: Record<string, unknown>[],
64	  columns: string[],
65	): string {
66	  const header = columns.map(csvEscapeCell).join(',');
67	  const body = objects
68	    .map((obj) => columns.map((c) => csvEscapeCell(obj[c])).join(','))
69	    .join('\r\n');
70	  return body ? `${header}\r\n${body}` : header;
71	}
