76	export function requireRole(...roles: UserRole[]) {
77	  return (req: AuthenticatedRequest, _res: Response, next: NextFunction): void => {
78	    if (!req.user) {
79	      next(new AppError(
80	        ErrorCodes.UNAUTHORIZED.statusCode,
81	        ErrorCodes.UNAUTHORIZED.code,
82	        'Authentication required'
83	      ));
