1	/**
2	 * Unit tests for the room-night reporting SQL builder.
3	 *
4	 * These tests spy on `sequelize.query` and assert structural properties
5	 * of the generated SQL — they would fail loudly if the room-night
6	 * fix were ever silently reverted.
7	 */
8	
9	import { sequelize } from '../src/config/database';
10	import { occupancy, adr, revpar } from '../src/services/reporting.service';
11	
12	describe('reporting service — SQL fragment shape', () => {
13	  beforeEach(() => {
14	    (sequelize.query as jest.Mock).mockReset().mockResolvedValue([]);
15	  });
16	
17	  function lastSql(): string {
18	    return (sequelize.query as jest.Mock).mock.calls[0][0] as string;
19	  }
20	
21	  function lastReplacements(): unknown[] {
22	    return ((sequelize.query as jest.Mock).mock.calls[0][1] as { replacements: unknown[] }).replacements;
23	  }
24	
25	  describe('occupancy', () => {
26	    test('contains recursive calendar CTE', async () => {
27	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
28	      expect(lastSql()).toMatch(/WITH RECURSIVE calendar/);
29	    });
30	
31	    test('uses check-in inclusive, check-out exclusive', async () => {
32	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
33	      const sql = lastSql();
34	      expect(sql).toMatch(/cal\.night >= res\.check_in_date/);
35	      expect(sql).toMatch(/cal\.night <\s+res\.check_out_date/);
36	    });
37	
38	    test('excludes maintenance rooms from available count', async () => {
39	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
40	      expect(lastSql()).toMatch(/rm\.status <> 'maintenance'/);
41	    });
42	
43	    test('includes occupancy_rate column in output', async () => {
44	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
45	      expect(lastSql()).toMatch(/occupancy_rate/);
46	    });
47	
48	    test('NULLIF guards against zero available rooms', async () => {
49	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
50	      expect(lastSql()).toMatch(/NULLIF\(SUM\(available_rooms\), 0\)/);

90	
91	  describe('adr', () => {
92	    test('formula is revenue / occupied (room-nights)', async () => {
93	      await adr({ from: '2026-06-01', to: '2026-06-03' });
94	      expect(lastSql()).toMatch(/SUM\(revenue_cents\)\s*\/\s*NULLIF\(SUM\(occupied_rooms\), 0\)/);
95	    });
96	  });
97	
98	  describe('revpar', () => {
99	    test('formula is revenue / available (room-nights)', async () => {
100	      await revpar({ from: '2026-06-01', to: '2026-06-03' });
101	      expect(lastSql()).toMatch(/SUM\(revenue_cents\)\s*\/\s*NULLIF\(SUM\(available_rooms\), 0\)/);
102	    });
103	  });
104	
105	  // ─── SQL safety / parameterization ────────────────────────────────
106	  describe('SQL parameterization', () => {
107	    test('all dynamic values go through replacements (no string interpolation of user input)', async () => {
108	      await occupancy({
109	        from: '2026-06-01',
110	        to: '2026-06-30',
111	        propertyId: "p'-or-1=1",
112	        roomType: "rm'-or-1=1",
113	      });
114	      const sql = lastSql();
115	      const reps = lastReplacements();
116	
117	      // Dynamic values must NOT appear inline in the SQL string
118	      expect(sql).not.toContain("p'-or-1=1");
119	      expect(sql).not.toContain("rm'-or-1=1");
120	
121	      // They must be in the replacements array
122	      expect(reps).toContain("p'-or-1=1");
123	      expect(reps).toContain("rm'-or-1=1");
124	    });
125	
126	    test('groupBy enum is whitelisted — never reaches SQL as raw input', async () => {
127	      // Even with a hostile groupBy value, the SQL only contains one of
128	      // the three approved DATE_FORMAT expressions. The hostile string
129	      // is dropped at the periodExpr enum check.
130	      await occupancy({ from: '2026-06-01', to: '2026-06-30', groupBy: "'; DROP TABLE rooms; --" } as any);
131	      const sql = lastSql();
132	      expect(sql).not.toContain('DROP TABLE');
133	      // Falls back to the default day format
134	      expect(sql).toMatch(/DATE_FORMAT\(night, '%Y-%m-%d'\)/);
135	    });
136	  });
137	
138	  // ─── Boundary conditions ─────────────────────────────────────────
139	  describe('boundary conditions', () => {
140	    test('single-day range — calendar termination guard still produces a row', async () => {
141	      // The recursive CTE recurses while night < to. For from === to it
142	      // emits exactly the anchor row and stops, giving a single night.
143	      await occupancy({ from: '2026-06-01', to: '2026-06-01' });
144	      const sql = lastSql();
145	      // The anchor + termination guard pattern is what makes one-day
146	      // ranges work correctly.
147	      expect(sql).toMatch(/SELECT DATE\(\?\)/);
148	      expect(sql).toMatch(/WHERE night < DATE\(\?\)/);
149	      const reps = lastReplacements();
150	      // from + to = exactly two parameters (no extra propertyId/roomType)
151	      expect(reps).toEqual(['2026-06-01', '2026-06-01']);
152	    });
153	
154	    test('empty available set — NULLIF guard prevents divide-by-zero in occupancy', async () => {
155	      // Even when the result set is empty, the SQL generated should
156	      // still divide via NULLIF(sum, 0) so we get NULL not /0 error.
157	      (sequelize.query as jest.Mock).mockResolvedValueOnce([]);
158	      const result = await occupancy({ from: '2026-06-01', to: '2026-06-30' });
159	      expect(result).toEqual([]);
160	      // Reconfirm the divide expression is NULLIF-guarded.
161	      expect(lastSql()).toMatch(/NULLIF\(SUM\(available_rooms\), 0\)/);
162	    });
163	
164	    test('empty occupied set — adr/revpar both NULLIF-guarded', async () => {
165	      (sequelize.query as jest.Mock).mockReset().mockResolvedValue([]);
166	      await adr({ from: '2026-06-01', to: '2026-06-30' });
167	      expect((sequelize.query as jest.Mock).mock.calls[0][0]).toMatch(/NULLIF\(SUM\(occupied_rooms\), 0\)/);
168	
169	      (sequelize.query as jest.Mock).mockReset().mockResolvedValue([]);

170	      await revpar({ from: '2026-06-01', to: '2026-06-30' });
171	      expect((sequelize.query as jest.Mock).mock.calls[0][0]).toMatch(/NULLIF\(SUM\(available_rooms\), 0\)/);
172	    });
173	
174	    test('day/week/month rollups all start from the same per-night CTE', async () => {
175	      // The CTE definition (`per_night AS …`) must appear before the
176	      // SELECT in every rollup variant — otherwise different variants
177	      // could compute from different bases.
178	      for (const groupBy of ['day', 'week', 'month'] as const) {
179	        (sequelize.query as jest.Mock).mockReset().mockResolvedValue([]);
180	        await occupancy({ from: '2026-06-01', to: '2026-06-30', groupBy });
181	        const sql = (sequelize.query as jest.Mock).mock.calls[0][0] as string;
182	        expect(sql).toMatch(/per_night AS \(/);
183	        expect(sql).toMatch(/FROM per_night/);
184	      }
185	    });
186	  });
187	});
